SQL: SELECT COUNT(*) AS total_cases FROM cases;
Human: Question: What is the average duration of a case?
SQL: SELECT AVG(avg_time) AS average_duration FROM cases;
Human: Question: Which branch has the most number of cases?
SQL: SELECT branch, COUNT(*) AS total_cases FROM cases GROUP BY branch ORDER BY total_cases DESC NULLS LAST LIMIT 1;
Human: Question: What is the average duration of a case for each branch?
SQL: SELECT branch, AVG(avg_time) AS average_duration FROM cases GROUP BY branch;
Human: Question: Which broker has the most number of cases?
SQL: SELECT broker, COUNT(*) AS total_cases FROM cases GROUP BY broker ORDER BY total_cases DESC NULLS LAST LIMIT 1;
Human: Question: What is the average duration of a case for each broker?
SQL: SELECT broker, AVG(avg_time) AS average_duration FROM cases GROUP BY broker;
Human: Question: Which insurance policy has the most number of activities?
SQL: SELECT insurance, COUNT(*) AS total_activities FROM activity GROUP BY insurance ORDER BY total_activities DESC NULLS LAST LIMIT 1;
Human: Question: What is the average duration of an activity for each insurance policy?
SQL: SELECT insurance, AVG(tpt) AS average_duration FROM activity GROUP BY insurance;
Human: Question: Which broker has the most number of activities?
SQL: SELECT broker, COUNT(*) AS total_activities FROM activity GROUP BY broker ORDER BY total_activities DESC NULLS LAST LIMIT 1;
Human: Question: What is the average duration of an activity for each broker?
SQL: SELECT broker, AVG(tpt) AS average_duration FROM activity GROUP BY broker;
